const data=JSON.parse(document.getElementById('agentr-review-data').textContent);
const config=JSON.parse(document.getElementById('agentr-review-config').textContent);
const feedback=[];
const main=document.getElementById('main'); const panel=document.getElementById('feedbackPanel'); const wrap=document.querySelector('.wrap'); const splitter=document.getElementById('splitter');
const subsystemPalette={rwm:{fill:'#E0F2FE',stroke:'#0369A1',label:'RWM'},pg:{fill:'#DCFCE7',stroke:'#15803D',label:'PG'},ae:{fill:'#FDE68A',stroke:'#B45309',label:'AE'},la:{fill:'#FCE7F3',stroke:'#BE185D',label:'LA'},iac:{fill:'#EDE9FE',stroke:'#6D28D9',label:'IAC'}};
let currentWorkflowGraphEl=null; let currentTaskPreviewId=null; let currentSelectedWorkflowNodeId=null;
function esc(x){return String(x??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}
function val(x){return x===null||x===undefined||x===''?'':x;}
function section(title,id){const s=document.createElement('section');s.className='panel';s.id=id;s.innerHTML='<h2>'+esc(title)+'</h2>';main.appendChild(s);return s;}
function selectTarget(target,targetId,field){if(!config.include_feedback_panel)return;document.getElementById('fb_target').value=target;document.getElementById('fb_target_id').value=targetId||'';document.getElementById('fb_field').value=field||target;}
function jsonBlock(x){if(x===null||x===undefined)return'<pre>null</pre>';return'<pre>'+esc(JSON.stringify(x,null,2))+'</pre>';}
function arrayValue(x){return Array.isArray(x)?x:(x===null||x===undefined||x===''?[]:[x]);}
function knowledgeRefs(x){return arrayValue(x).map(String);}
function normalizeSubsystemKey(x){x=String(x||'').toLowerCase();return['rwm','pg','ae','la','iac'].includes(x)?x:'';}
function nodeSubsystem(id){const subsystemMap=(data.workflow_graph.metadata||{}).node_subsystems||(data.metadata||{}).node_subsystems||{};const labels=subsystemMap[id];const normalized=arrayValue(labels).map(normalizeSubsystemKey).filter(Boolean);return normalized.length?normalized[0]:'';}
function nodeColorTheme(){const sel=document.getElementById('workflow-theme-select');return sel?sel.value:(config.node_color_theme||'default');}
function baseWorkflowCategory(n){if(n.human_required)return{key:'human',fill:'#FFF1D6',stroke:'#B45309',label:'Human gate'};if(String(val(n.automation_status))==='llm_assisted'||String(val(n.automation_status))==='external_llm')return{key:'external',fill:'#E9E4FB',stroke:'#6D28D9',label:'External stochastic LLM'};return{key:'deterministic',fill:'#E8F3EE',stroke:'#607466',label:'Deterministic automation'};}
function nodeKind(n){const k=String(val(n&&n.node_kind)||'action').toLowerCase();return['action','knowledge','memory','file','api','schema','data'].includes(k)?k:'action';}
function isDataNode(n){return nodeKind(n)!=='action';}
function dataNodeVisual(n){const k=nodeKind(n);const map={knowledge:{key:'knowledge',fill:'#DBEAFE',stroke:'#1D4ED8',label:'Knowledge data'},memory:{key:'memory',fill:'#DCFCE7',stroke:'#15803D',label:'Memory data'},file:{key:'file',fill:'#FEF3C7',stroke:'#B45309',label:'File data'},api:{key:'api',fill:'#E0F2FE',stroke:'#0369A1',label:'API data'},schema:{key:'schema',fill:'#F3E8FF',stroke:'#7E22CE',label:'Schema data'},data:{key:'data',fill:'#F3F4F6',stroke:'#4B5563',label:'Data resource'}};return map[k]||map.data;}
function categoryPriority(key){return key==='human'?3:key==='external'?2:1;}
function effectiveWorkflowCategory(n){const base=baseWorkflowCategory(n);let best=base;const nested=(n&&n.nested_workflow&&n.nested_workflow.nodes)||[];nested.forEach(child=>{const childCategory=effectiveWorkflowCategory(child);if(categoryPriority(childCategory.key)>categoryPriority(best.key))best=childCategory;});return best;}
function nodeVisual(n){if(isDataNode(n))return dataNodeVisual(n);if(nodeColorTheme()==='subsystems'){const key=nodeSubsystem(n.id);if(key&&subsystemPalette[key])return subsystemPalette[key];return{fill:'#EEF2F7',stroke:'#7B8794',label:'Unlabeled'};}return effectiveWorkflowCategory(n);}
function hasNestedWorkflow(n){return!!(n&&((n.nested_workflow&&Array.isArray(n.nested_workflow.nodes)&&n.nested_workflow.nodes.length)||val(n.subworkflow_ref)));}
function hasSubworkflow(n){return hasNestedWorkflow(n)||!!val(n&&n.subworkflow_ref);}
function workflowNodeById(id){return(data.workflow_graph.nodes||[]).find(n=>n.id===id);}
function workflowEdgeByIndex(index,edges){return((edges||[])[index])||null;}
function actionNodes(nodes){return(nodes||[]).filter(n=>!isDataNode(n));}
function workflowActionNodes(){return actionNodes(data.workflow_graph.nodes||[]);}
function workflowActionEdges(nodes,edges){const ids=new Set((nodes||[]).map(n=>n.id));return(edges||[]).filter(e=>ids.has(e.from)&&ids.has(e.to));}
function renderDetailObject(n,note,boxId='node_detail'){const box=document.getElementById(boxId);if(!box)return;const refs=knowledgeRefs(n.knowledge_refs).join(', ');const linked=arrayValue(n.linked_spec_ids).map(String).join(', ');const hasNested=n.nested_workflow&&n.nested_workflow.nodes;const hasRef=!!val(n.subworkflow_ref);const subsystem=nodeSubsystem(n.id);const category=isDataNode(n)?dataNodeVisual(n):(nodeColorTheme()==='subsystems'?(subsystemPalette[subsystem]||{label:'Unlabeled'}):effectiveWorkflowCategory(n));box.innerHTML=`<div class='detail-box'><div class='id'>${esc(n.id)}</div><div class='label'>${esc(n.label)}</div>${note?`<div class='small'>${esc(note)}</div>`:''}<div class='detail-kv'><b>Node kind</b><span>${esc(nodeKind(n))}</span><b>Rule</b><span>${esc(val(n.rule_spec))}</span><b>Owner</b><span>${esc(val(n.owner))}</span><b>Automation</b><span>${esc(val(n.automation_status))}</span><b>Human gate</b><span>${esc(n.human_required)}</span><b>Category</b><span>${esc(category.label||'')}</span><b>Subsystem</b><span>${esc(subsystem||'')}</span><b>Source path</b><span>${esc(val(n.source_path))}</span><b>Retrieval</b><span>${esc(val(n.retrieval_mode))}</span><b>Persistence</b><span>${esc(val(n.persistence))}</span><b>Linked specs</b><span>${esc(linked)}</span><b>Hint</b><span>${esc(val(n.implementation_hint))}</span><b>Knowledge</b><span>${esc(refs)}</span><b>Subworkflow</b><span>${esc(val(n.subworkflow_ref))}</span></div><h3>Input schema</h3>${jsonBlock(n.input_schema||{})}<h3>Output schema</h3>${jsonBlock(n.output_schema||{})}${hasNested?'<div class="small">Click the subworkflow badge on the graph node to open the embedded subworkflow.</div>':(hasRef?'<div class="small">This node references a subworkflow, but it was not embedded in this review bundle.</div>':'')}</div>`;}
function renderNodeDetail(id){const n=workflowNodeById(id);if(!n){renderDetailObject({id:'',label:'Click a workflow node or edge to inspect its details.'},'');return;}renderDetailObject(n,isDataNode(n)?'Workflow resource node':'Top-level workflow node');if(!isDataNode(n)){currentSelectedWorkflowNodeId=id;renderResourcePanel(id);}}
function renderNestedNodeDetail(parentId,nodeId,boxId='node_detail'){const parent=workflowNodeById(parentId);const n=parent&&parent.nested_workflow&&parent.nested_workflow.nodes?(parent.nested_workflow.nodes||[]).find(x=>x.id===nodeId):null;if(!n)return;renderDetailObject(n,'Nested node inside '+parentId,boxId);if(boxId==='subworkflow_node_detail')renderSubworkflowResourcePanel(parent,nodeId);selectTarget('workflow_node',parentId+'::'+nodeId,'workflow.nodes.'+parentId+'.nested_workflow.nodes.'+nodeId);}
function renderEdgeDetailObject(e,note,nodes,boxId='node_detail'){const box=document.getElementById(boxId);if(!box)return;const a=(nodes||[]).find(n=>n.id===e.from)||workflowNodeById(e.from)||{};const b=(nodes||[]).find(n=>n.id===e.to)||workflowNodeById(e.to)||{};box.innerHTML=`<div class='detail-box'><div class='id'>${esc(e.from)} -> ${esc(e.to)}</div><div class='label'>${esc(val(e.relation)||'depends_on')}</div>${note?`<div class='small'>${esc(note)}</div>`:''}<div class='detail-kv'><b>From id</b><span>${esc(e.from)}</span><b>From label</b><span>${esc(val(a.label))}</span><b>To id</b><span>${esc(e.to)}</span><b>To label</b><span>${esc(val(b.label))}</span><b>Relation</b><span>${esc(val(e.relation)||'depends_on')}</span><b>Condition</b><span>${esc(val(e.condition))}</span><b>Branch group</b><span>${esc(val(e.branch_group))}</span><b>Mutually exclusive</b><span>${esc(val(e.mutually_exclusive))}</span><b>Confidence</b><span>${esc(val(e.confidence))}</span><b>Notes</b><span>${esc(val(e.notes))}</span></div></div>`;}
function renderWorkflowEdge(index,edges){const e=workflowEdgeByIndex(index,edges);if(!e)return;renderEdgeDetailObject(e,'Workflow edge',data.workflow_graph.nodes||[]);selectTarget('workflow_edge',e.from+'->'+e.to,'workflow.edges');}
function selectWorkflowNode(id){renderNodeDetail(id);selectTarget('workflow_node',id,'workflow.nodes.'+id);}
function wrapSvgText(text,maxChars=22){const words=String(text??'').split(/\s+/).filter(Boolean);const lines=[];let line='';const pushLong=w=>{while(w.length>maxChars){lines.push(w.slice(0,maxChars));w=w.slice(maxChars);}return w;};words.forEach(word=>{word=pushLong(word);if(!word)return;if(!line){line=word;}else if((line+' '+word).length<=maxChars){line+=' '+word;}else{lines.push(line);line=word;}});if(line)lines.push(line);return lines.length?lines:[''];}
function svgTspans(lines,x,startDy,lineHeight){return lines.map((line,i)=>`<tspan x='${x}' dy='${i===0?startDy:lineHeight}'>${esc(line)}</tspan>`).join('');}
function prepareWorkflowNodes(nodes){nodes.forEach(n=>{n._lines=wrapSvgText(n.label,24);n._h=Math.max(54,26+n._lines.length*15);});}
function hasBackwardEdges(nodes,edges){const order=Object.fromEntries((nodes||[]).map((n,i)=>[n.id,i]));return(edges||[]).some(e=>Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&order[e.to]<=order[e.from]);}
function layoutWorkflowGrid(nodes,opt){const rows=Math.max(1,Math.ceil(nodes.length/3));nodes.forEach((n,i)=>{n._row=Math.floor(i/3);n._x=opt.left+(i%3)*opt.colGap;});const rowHeights=[];for(let r=0;r<rows;r++){const rowNodes=nodes.filter(n=>n._row===r);rowHeights[r]=rowNodes.length?Math.max(...rowNodes.map(n=>n._h)):62;}let cursor=opt.top;for(let r=0;r<rows;r++){nodes.filter(n=>n._row===r).forEach(n=>{n._y=cursor;});cursor+=rowHeights[r]+opt.rowGap;}return Math.max(190,cursor-opt.rowGap+opt.top);}
function dagDepth(nodes,edges){const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const order=Object.fromEntries(nodes.map((n,i)=>[n.id,i]));const indeg=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(byId[e.from]&&byId[e.to])indeg[e.to]=(indeg[e.to]||0)+1;});const q=nodes.filter(n=>(indeg[n.id]||0)===0).map(n=>n.id);const depth=Object.fromEntries(nodes.map(n=>[n.id,0]));const processed=new Set();let guard=0;while(q.length&&guard++<nodes.length*nodes.length){const id=q.shift();processed.add(id);edges.filter(e=>e.from===id&&byId[e.to]).forEach(e=>{depth[e.to]=Math.max(depth[e.to]||0,(depth[id]||0)+1);indeg[e.to]-=1;if(indeg[e.to]===0)q.push(e.to);});}if(processed.size<nodes.length){nodes.forEach(n=>{depth[n.id]=0;});for(let pass=0;pass<nodes.length;pass++){let changed=false;edges.forEach(e=>{if(byId[e.from]&&byId[e.to]&&order[e.to]>order[e.from]){const d=(depth[e.from]||0)+1;if(d>(depth[e.to]||0)){depth[e.to]=d;changed=true;}}});if(!changed)break;}}return depth;}
function layoutWorkflowLayered(nodes,edges,opt){const depth=dagDepth(nodes,edges);nodes.forEach((n,i)=>{n._depth=depth[n.id]??i;n._col=n._depth;n._row=0;});const maxDepth=nodes.length?Math.max(...nodes.map(n=>n._depth)):0;const maxCols=4;if(maxDepth>=maxCols){nodes.forEach(n=>{n._band=Math.floor(n._depth/maxCols);n._col=n._depth%maxCols;});const bands=[...new Set(nodes.map(n=>n._band))].sort((a,b)=>a-b);let y=opt.top;bands.forEach(band=>{const bandNodes=nodes.filter(n=>n._band===band);const groups={};bandNodes.forEach(n=>{const k=String(n._col);if(!groups[k])groups[k]=[];groups[k].push(n);});let bandHeight=70;Object.keys(groups).forEach(k=>{groups[k].sort((a,b)=>String(a.id).localeCompare(String(b.id)));const stackHeight=groups[k].reduce((sum,n)=>sum+n._h+opt.rowGap/2,0);bandHeight=Math.max(bandHeight,stackHeight);});Object.keys(groups).forEach(k=>{let stackY=y;groups[k].forEach((n,ri)=>{n._x=opt.left+n._col*opt.colGap;n._y=stackY;n._row=ri;stackY+=n._h+opt.rowGap/2;});});y+=bandHeight+opt.rowGap*2;});return Math.max(190,y-opt.rowGap);}const cols=[...new Set(nodes.map(n=>n._col))].sort((a,b)=>a-b);let maxBottom=0;cols.forEach((col,ci)=>{const colNodes=nodes.filter(n=>n._col===col);let y=opt.top;colNodes.forEach((n,ri)=>{n._x=opt.left+ci*opt.colGap;n._y=y;n._row=ri;y+=n._h+opt.rowGap;maxBottom=Math.max(maxBottom,n._y+n._h+opt.top);});});return Math.max(190,maxBottom);}
function positionResourceNodes(nodes,edges,opt){const resources=nodes.filter(isDataNode);if(!resources.length)return;const actions=nodes.filter(n=>!isDataNode(n)&&Number.isFinite(n._x));const minActionX=actions.length?Math.min(...actions.map(n=>n._x)):opt.left+opt.nodeW+120;const resourceX=minActionX-opt.nodeW-120;const actionOrder=Object.fromEntries(actions.map((n,i)=>[n.id,i]));resources.sort((a,b)=>{const firstA=Math.min(...edges.filter(e=>e.from===a.id||e.to===a.id).map(e=>actionOrder[e.from]??actionOrder[e.to]??9999),9999);const firstB=Math.min(...edges.filter(e=>e.from===b.id||e.to===b.id).map(e=>actionOrder[e.from]??actionOrder[e.to]??9999),9999);return firstA-firstB||nodeKind(a).localeCompare(nodeKind(b))||String(a.id).localeCompare(String(b.id));});let y=opt.top;resources.forEach(n=>{n._x=resourceX;n._y=y;n._resourceLane='Resource data';y+=n._h+opt.rowGap;});nodes.filter(isDataNode).forEach(n=>{n._depth=-1;n._processIndex=-1;});}
function layoutWorkflowProcess(nodes,edges,opt){const order=Object.fromEntries(nodes.map((n,i)=>[n.id,i]));const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const out=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to]))out[e.from]=(out[e.from]||0)+1;});const branchBySource={};edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&isBranchEdge(e)){if(!branchBySource[e.from])branchBySource[e.from]=[];branchBySource[e.from].push(e);}});Object.keys(branchBySource).forEach(src=>{if(branchBySource[src].length<2)delete branchBySource[src];});const branchIds=new Set();Object.values(branchBySource).forEach(group=>group.forEach(e=>branchIds.add(e.to)));const decisionJoinIds=new Set();const decisionJoinBySource={};Object.entries(branchBySource).forEach(([src,group])=>{const downstream=group.map(e=>new Set(edges.filter(edge=>edge.from===e.to).map(edge=>edge.to)));if(!downstream.length)return;const common=[...downstream[0]].filter(id=>downstream.every(set=>set.has(id)));if(common.length){const joinId=common.sort((a,b)=>(order[a]??9999)-(order[b]??9999))[0];decisionJoinBySource[src]=joinId;decisionJoinIds.add(joinId);}});edges.forEach(e=>{if(Number.isFinite(order[e.from])&&Number.isFinite(order[e.to])&&order[e.to]>order[e.from]+1&&(out[e.to]||0)===0)branchIds.add(e.to);});nodes.forEach((n,i)=>{n._processIndex=i;n._depth=i;n._processBranch=branchIds.has(n.id);n._processBranchSource='';n._decisionJoin=decisionJoinIds.has(n.id);n._processBranchLane=null;delete n._x;delete n._y;});let y=opt.top;const spineX=opt.left+120;const branchGap=Math.max(opt.colGap,320);nodes.forEach(n=>{if(n._processBranch)return;if(n._decisionJoin&&Number.isFinite(n._y)){y=Math.max(y,n._y+n._h+opt.rowGap);return;}n._x=spineX;n._y=y;y+=n._h+opt.rowGap;const group=branchBySource[n.id];if(group){const targets=group.map(e=>byId[e.to]).filter(Boolean);const count=targets.length;const startX=n._x-((count-1)*branchGap)/2;const branchY=n._y+n._h+opt.rowGap;let maxBranchBottom=n._y+n._h;targets.forEach((b,idx)=>{b._processBranch=true;b._processBranchSource=n.id;b._x=startX+idx*branchGap;b._y=branchY;b._processBranchLane=idx;maxBranchBottom=Math.max(maxBranchBottom,b._y+b._h);});const join=byId[decisionJoinBySource[n.id]];if(join&&!branchIds.has(join.id)){join._decisionJoin=true;join._x=spineX;join._y=maxBranchBottom+opt.rowGap;y=Math.max(y,join._y+join._h+opt.rowGap);}}});const branchCount={};edges.forEach(e=>{const a=byId[e.from],b=byId[e.to];if(a&&b&&b._processBranch&&!Number.isFinite(b._y)){branchCount[a.id]=(branchCount[a.id]||0)+1;b._processBranchSource=a.id;b._x=spineX+branchGap;b._y=a._y+(branchCount[a.id]-1)*(b._h+opt.rowGap/2);}});nodes.filter(n=>n._processBranch&&!Number.isFinite(n._y)).forEach(n=>{n._x=spineX+branchGap;n._y=y;y+=n._h+opt.rowGap;});positionResourceNodes(nodes,edges,opt);const minNodeX=nodes.length?Math.min(...nodes.map(n=>n._x)):spineX;edges.forEach(e=>{const a=byId[e.from],b=byId[e.to];if(a&&b&&a._processBranch&&!b._processBranch){e._branchRejoin=true;e._branchRejoinSide=a._x<b._x?'left':'right';e._branchRailX=e._branchRejoinSide==='left'?Math.min(a._x,b._x)-58:Math.max(a._x+opt.nodeW,b._x+opt.nodeW)+58;}});const feedbackEdges=edges.filter(e=>{const a=byId[e.from],b=byId[e.to];return a&&b&&Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&b._processIndex<a._processIndex;}).sort((e1,e2)=>((order[e2.from]-order[e2.to])-(order[e1.from]-order[e1.to])));feedbackEdges.forEach((e,idx)=>{e._feedbackRailX=minNodeX-140-idx*56;});const maxBottom=nodes.length?Math.max(...nodes.map(n=>n._y+n._h+opt.top)):190;return Math.max(190,maxBottom);}
function laneLabel(n){const owner=val(n.owner);if(owner)return'owner: '+owner;const automation=val(n.automation_status);if(automation)return'automation: '+automation;return n.human_required?'human gate':'no human gate';}
function layoutWorkflowSwimlane(nodes,edges,opt){const depth=dagDepth(nodes,edges);nodes.forEach((n,i)=>{n._lane=laneLabel(n);n._col=depth[n.id]??i;});const lanes=[];nodes.forEach(n=>{if(!lanes.includes(n._lane))lanes.push(n._lane);});let y=opt.top;lanes.forEach(lane=>{const laneNodes=nodes.filter(n=>n._lane===lane).sort((a,b)=>(a._col-b._col)||String(a.id).localeCompare(String(b.id)));const colGroups={};laneNodes.forEach(n=>{const k=String(n._col);if(!colGroups[k])colGroups[k]=[];colGroups[k].push(n);});let laneHeight=92;Object.keys(colGroups).forEach(k=>{const stack=colGroups[k];const stackHeight=24+stack.reduce((sum,n)=>sum+n._h+opt.rowGap/2,0);laneHeight=Math.max(laneHeight,stackHeight);});Object.keys(colGroups).forEach(k=>{let stackY=y+24;colGroups[k].forEach(n=>{n._x=opt.left+150+n._col*opt.colGap;n._y=stackY;stackY+=n._h+opt.rowGap/2;});});laneNodes.forEach(n=>{n._laneY=y;n._laneH=laneHeight;});y+=laneHeight+opt.rowGap;});return Math.max(190,y-opt.rowGap+opt.top);}
function isBranchEdge(e){return String(val(e.relation)).includes('branch')||!!val(e.condition)||!!val(e.branch_group)||e.mutually_exclusive===true;}
function isResourceEdge(e){return['reads','writes','updates','prompts_with','validates_against','produces'].includes(String(val(e.relation)));}
function edgeVisual(e){if(isBranchEdge(e))return{stroke:'#B45309',dash:'6 4',marker:'url(#arrow-branch)',labelFill:'#FFF7E6',labelStroke:'#D69E2E'};if(isResourceEdge(e))return{stroke:'#2563EB',dash:String(val(e.relation))==='reads'||String(val(e.relation))==='prompts_with'?'4 3':'',marker:'url(#arrow)',labelFill:'#EFF6FF',labelStroke:'#93C5FD'};return{stroke:'#6b7280',dash:'',marker:'url(#arrow)',labelFill:'#fffdf7',labelStroke:'#d7cebd'};}
function edgeLabel(e){if(val(e.condition))return String(e.condition);if(isBranchEdge(e)&&val(e.relation))return String(e.relation);if(isResourceEdge(e))return String(e.relation);return'';}
function edgeLabelPosition(a,b,e={}){if(isBranchEdge(e)&&b._processBranch){return{x:b._x+90,y:Math.min(a._y+a._h+22,b._y-10)};}return{x:(a._x+b._x)/2+90,y:(a._cy+b._cy)/2-6};}
function edgeAnchors(a,b,nodeW){const acx=a._x+nodeW/2,bcx=b._x+nodeW/2,dy=b._cy-a._cy,dx=bcx-acx;if(Math.abs(dx)<nodeW*0.35&&Math.abs(dy)>8){if(dy>=0)return{sx:acx,sy:a._y+a._h,tx:bcx,ty:b._y,axis:'vertical'};return{sx:acx,sy:a._y,tx:bcx,ty:b._y+b._h,axis:'vertical'};}if(dx>=0)return{sx:a._x+nodeW,sy:a._cy,tx:b._x,ty:b._cy,axis:'horizontal'};return{sx:a._x,sy:a._cy,tx:b._x+nodeW,ty:b._cy,axis:'horizontal'};}
function edgePath(a,b,nodeW,style,index,e={}){const p=edgeAnchors(a,b,nodeW);const sx=p.sx,sy=p.sy,tx=p.tx,ty=p.ty;const offset=((index%5)-2)*10;const feedback=(Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&b._processIndex<a._processIndex)||(Number.isFinite(a._depth)&&Number.isFinite(b._depth)&&b._depth<a._depth);if(style==='straight')return`M ${sx} ${sy} L ${tx} ${ty}`;if(style==='orthogonal'){if(isBranchEdge(e)&&b._processBranch&&!e._branchRejoin){const left=b._x<a._x;const startX=left?a._x:a._x+nodeW;const startY=a._cy;const endX=b._x+nodeW/2;const endY=b._y;return`M ${startX} ${startY} L ${endX} ${startY} L ${endX} ${endY}`;}if(e._branchRejoin){const left=e._branchRejoinSide==='left';const railX=Number.isFinite(e._branchRailX)?e._branchRailX:(left?Math.min(a._x,b._x)-58:Math.max(a._x+nodeW,b._x+nodeW)+58);const startX=left?a._x:a._x+nodeW;const endX=left?b._x:b._x+nodeW;return`M ${startX} ${a._cy} L ${railX} ${a._cy} L ${railX} ${b._cy} L ${endX} ${b._cy}`;}if(feedback){const sameProcessColumn=Number.isFinite(a._processIndex)&&Number.isFinite(b._processIndex)&&Math.abs(a._x-b._x)<2;const startX=sameProcessColumn?a._x:a._x+nodeW/2;const endX=sameProcessColumn?b._x:b._x+nodeW/2;const startY=sameProcessColumn?a._cy:(b._y<a._y?a._y:a._y+a._h);const endY=sameProcessColumn?b._cy:(b._y<a._y?b._y+b._h:b._y);const railX=Number.isFinite(e._feedbackRailX)?e._feedbackRailX:Math.min(a._x,b._x)-58-Math.abs(offset);return`M ${startX} ${startY} L ${railX} ${startY} L ${railX} ${endY} L ${endX} ${endY}`;}if(Math.abs(sy-ty)<2||Math.abs(sx-tx)<2)return`M ${sx} ${sy} L ${tx} ${ty}`;if(p.axis==='vertical'){const midY=(sy+ty)/2+offset;return`M ${sx} ${sy} L ${sx} ${midY} L ${tx} ${midY} L ${tx} ${ty}`;}const midX=(sx+tx)/2+offset;return`M ${sx} ${sy} L ${midX} ${sy} L ${midX} ${ty} L ${tx} ${ty}`;}const dx=Math.max(40,Math.abs(tx-sx)*0.45);return`M ${sx} ${sy} C ${sx+dx+offset} ${sy}, ${tx-dx+offset} ${ty}, ${tx} ${ty}`;}
function drawWorkflowGraph(el,nodes,edges,onNodeClick,onEdgeClick){
nodes=(nodes||[]).map(n=>({...n}));edges=(edges||[]).map(e=>({...e}));
onNodeClick=onNodeClick||selectWorkflowNode;onEdgeClick=onEdgeClick||((index)=>renderWorkflowEdge(index,edges));
const opt={nodeW:180,colGap:250,rowGap:34,top:34,left:48};
prepareWorkflowNodes(nodes);
let h;
if(config.graph_layout==='layered'){h=layoutWorkflowLayered(nodes,edges,opt);}
else if(config.graph_layout==='swimlane'){h=layoutWorkflowSwimlane(nodes,edges,opt);}
else if(config.graph_layout==='process'){h=layoutWorkflowProcess(nodes,edges,opt);}
else{h=layoutWorkflowGrid(nodes,opt);}
nodes.forEach(n=>{n._cy=n._y+n._h/2;});
const maxRight=nodes.length?Math.max(...nodes.map(n=>n._x+opt.nodeW+opt.left)):820;
const minLeft=nodes.length?Math.min(...nodes.map(n=>n._x)):0;
const minEdgeX=edges.length?Math.min(...edges.map(e=>Math.min(Number.isFinite(e._feedbackRailX)?e._feedbackRailX:Infinity,Number.isFinite(e._branchRailX)?e._branchRailX:Infinity))):Infinity;
const maxEdgeX=edges.length?Math.max(...edges.map(e=>Math.max(Number.isFinite(e._branchRailX)?e._branchRailX:-Infinity,Number.isFinite(e._feedbackRailX)?e._feedbackRailX:-Infinity))):-Infinity;
const viewLeft=Math.min(0,minLeft-80,Number.isFinite(minEdgeX)?minEdgeX-40:0);
const viewRight=Math.max(maxRight,Number.isFinite(maxEdgeX)?maxEdgeX+opt.left+40:0);
const w=Math.max(820,viewRight-viewLeft);
let svg=`<svg viewBox='${viewLeft} 0 ${w} ${h}' width='${w}' height='${h}' role='img' aria-label='Workflow graph'>`;
svg+=`<defs><marker id='arrow' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#6b7280'/></marker><marker id='arrow-branch' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#B45309'/></marker></defs>`;
if(config.graph_layout==='swimlane'){
const lanes=[...new Set(nodes.map(n=>n._lane))];
lanes.forEach(lane=>{const n=nodes.find(x=>x._lane===lane);if(n){svg+=`<rect x='${opt.left}' y='${n._laneY}' width='${w-opt.left*2}' height='${n._laneH}' rx='10' fill='${lanes.indexOf(lane)%2?'#f3efe5':'#faf7ef'}' stroke='#d7cebd'/><text x='${opt.left+12}' y='${n._laneY+20}' font-size='12' fill='#52606d'>${esc(lane)}</text>`;}});
}
edges.forEach((e,i)=>{const a=nodes.find(n=>n.id===e.from),b=nodes.find(n=>n.id===e.to);if(a&&b){const visual=edgeVisual(e);const label=edgeLabel(e);svg+=`<path data-edge-index='${i}' d='${edgePath(a,b,opt.nodeW,config.edge_style,i,e)}' fill='none' stroke='${visual.stroke}' stroke-width='${isBranchEdge(e)?2:1.5}' stroke-dasharray='${visual.dash}' marker-end='${visual.marker}' style='pointer-events:stroke;cursor:pointer'/>`;if(label){const pos=edgeLabelPosition(a,b,e);const text=esc(label);const labelW=Math.min(210,Math.max(44,text.length*6.8+16));svg+=`<g data-edge-index='${i}' style='cursor:pointer'><rect x='${pos.x-labelW/2}' y='${pos.y-15}' width='${labelW}' height='20' rx='4' fill='${visual.labelFill}' stroke='${visual.labelStroke}'/><text x='${pos.x}' y='${pos.y}' text-anchor='middle' font-size='11' fill='#374151'>${text}</text></g>`;}}});
nodes.forEach(n=>{const tx=n._x+opt.nodeW/2;const visual=nodeVisual(n);const titleText=`${n.label} (${visual.label||''})`;const nested=hasNestedWorkflow(n);svg+=`<g tabindex='0' role='button' data-node-id='${esc(n.id)}'><title>${esc(titleText)}${nested?' - subworkflow':''}</title><rect x='${n._x}' y='${n._y}' width='${opt.nodeW}' height='${n._h}' rx='8' fill='${visual.fill}' stroke='${visual.stroke}'/>${nested?`<g data-subworkflow-id='${esc(n.id)}' class='subworkflow-badge' role='button' aria-label='Open subworkflow'><rect x='${n._x+opt.nodeW-24}' y='${n._y+8}' width='16' height='16' rx='4' fill='${visual.stroke}' stroke='${visual.stroke}'/><path d='M ${n._x+opt.nodeW-20} ${n._y+14} L ${n._x+opt.nodeW-16} ${n._y+10} L ${n._x+opt.nodeW-12} ${n._y+14} L ${n._x+opt.nodeW-16} ${n._y+18} Z' fill='#fff'/></g>`:''}<text text-anchor='middle' font-size='12'>${svgTspans(n._lines,tx,n._y+28,15)}</text></g>`;});
svg+='</svg>';el.innerHTML=`<div class='graph-scroll'>${svg}</div>`;
el.querySelectorAll('[data-node-id]').forEach(x=>{x.onclick=()=>onNodeClick(x.getAttribute('data-node-id'));});
el.querySelectorAll('[data-edge-index]').forEach(x=>{x.onclick=()=>onEdgeClick(Number(x.getAttribute('data-edge-index')));});
el.querySelectorAll('[data-subworkflow-id]').forEach(x=>{x.onclick=e=>{e.stopPropagation();openSubworkflowModal(x.getAttribute('data-subworkflow-id'));};});
}
function reviewGraphVisual(n){const kind=String(n.kind||n.node_type||n.memory_type||'item');const palette={root:{fill:'#F3F4F6',stroke:'#374151'},context:{fill:'#DBEAFE',stroke:'#1D4ED8'},semantic:{fill:'#DCFCE7',stroke:'#15803D'},episodic:{fill:'#FEF3C7',stroke:'#B45309'},procedural:{fill:'#FCE7F3',stroke:'#BE185D'},knowledge_item:{fill:'#DBEAFE',stroke:'#1D4ED8'},graph_node:{fill:'#EDE9FE',stroke:'#6D28D9'},domain:{fill:'#F3E8FF',stroke:'#7E22CE'},type:{fill:'#ECFDF5',stroke:'#047857'}};return palette[kind]||{fill:'#F3F4F6',stroke:'#6B7280'};}
function layoutReviewGraph(nodes,edges,opt){const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const indeg=Object.fromEntries(nodes.map(n=>[n.id,0]));edges.forEach(e=>{if(byId[e.from]&&byId[e.to])indeg[e.to]=(indeg[e.to]||0)+1;});const depth=Object.fromEntries(nodes.map(n=>[n.id,0]));const q=nodes.filter(n=>(indeg[n.id]||0)===0).map(n=>n.id);let guard=0;while(q.length&&guard++<nodes.length*nodes.length){const id=q.shift();edges.filter(e=>e.from===id&&byId[e.to]).forEach(e=>{depth[e.to]=Math.max(depth[e.to]||0,(depth[id]||0)+1);indeg[e.to]-=1;if(indeg[e.to]===0)q.push(e.to);});}const groups={};nodes.forEach((n,i)=>{n._lines=wrapSvgText(n.label||n.id,28);n._h=Math.max(58,28+n._lines.length*15);n._depth=depth[n.id]||0;if(!groups[n._depth])groups[n._depth]=[];groups[n._depth].push(n);});let maxBottom=0;Object.keys(groups).sort((a,b)=>Number(a)-Number(b)).forEach(k=>{let y=opt.top;groups[k].forEach((n,i)=>{n._x=opt.left+Number(k)*opt.colGap;n._y=y;n._cy=n._y+n._h/2;maxBottom=Math.max(maxBottom,n._y+n._h+opt.top);y+=n._h+opt.rowGap;});});return Math.max(180,maxBottom);}
function prepareReviewEdgeLanes(nodes,edges){const byId=Object.fromEntries(nodes.map(n=>[n.id,n]));const out={},inc={};edges.forEach((e,i)=>{if(!byId[e.from]||!byId[e.to])return;const ok=e.from,ik=e.to;if(!out[ok])out[ok]=[];if(!inc[ik])inc[ik]=[];out[ok].push(i);inc[ik].push(i);});edges.forEach((e,i)=>{const os=out[e.from]||[i],is=inc[e.to]||[i];e._outIndex=Math.max(0,os.indexOf(i));e._outTotal=os.length;e._inIndex=Math.max(0,is.indexOf(i));e._inTotal=is.length;});}
function reviewEdgeAnchor(node,total,index,side,opt){if(!node)return{x:0,y:0};const slots=Math.max(1,total||1);const pad=Math.min(22,Math.max(10,node._h*.18));const usable=Math.max(1,node._h-pad*2);const y=node._y+pad+usable*((index+.5)/slots);return{x:side==='right'?node._x+opt.nodeW:node._x,y};}
function drawReviewGraph(el,nodes,edges,onNodeClick,onEdgeClick,title='Design graph'){nodes=(nodes||[]).map(n=>({...n}));edges=(edges||[]).map(e=>({...e}));if(!nodes.length){el.innerHTML='';return;}const opt={nodeW:220,colGap:320,rowGap:42,top:36,left:52};const h=layoutReviewGraph(nodes,edges,opt);prepareReviewEdgeLanes(nodes,edges);const maxRight=Math.max(...nodes.map(n=>n._x+opt.nodeW+opt.left));const w=Math.max(760,maxRight);let svg=`<svg viewBox='0 0 ${w} ${h}' width='${w}' height='${h}' role='img' aria-label='${esc(title)}'>`;svg+=`<defs><marker id='arrow-review' viewBox='0 0 10 10' refX='8' refY='5' markerWidth='6' markerHeight='6' orient='auto-start-reverse'><path d='M 0 0 L 10 5 L 0 10 z' fill='#6b7280'/></marker></defs>`;edges.forEach((e,i)=>{const a=nodes.find(n=>n.id===e.from),b=nodes.find(n=>n.id===e.to);if(!a||!b)return;const start=reviewEdgeAnchor(a,e._outTotal,e._outIndex,'right',opt),end=reviewEdgeAnchor(b,e._inTotal,e._inIndex,'left',opt);const sx=start.x,sy=start.y,tx=end.x,ty=end.y,lane=(e._outIndex-(e._outTotal-1)/2)*18,mid=(sx+tx)/2+lane;svg+=`<path data-review-edge-index='${i}' d='M ${sx} ${sy} C ${mid} ${sy}, ${mid} ${ty}, ${tx} ${ty}' fill='none' stroke='#6b7280' stroke-width='1.25' marker-end='url(#arrow-review)' style='pointer-events:stroke;cursor:pointer'/>`;if(e.relation){const label=String(e.relation),lx=mid,ly=(sy+ty)/2-8+(e._inIndex-(e._inTotal-1)/2)*12,lw=Math.min(120,Math.max(34,label.length*6+14));svg+=`<rect x='${lx-lw/2}' y='${ly-12}' width='${lw}' height='16' rx='4' fill='#fbfaf6' stroke='#d7cebd'/>`;svg+=`<text x='${lx}' y='${ly}' text-anchor='middle' font-size='10' fill='#52606d'>${esc(label)}</text>`;}});nodes.forEach(n=>{const visual=reviewGraphVisual(n),tx=n._x+opt.nodeW/2;svg+=`<g tabindex='0' role='button' data-review-node-id='${esc(n.id)}'><title>${esc(n.id)}</title><rect x='${n._x}' y='${n._y}' width='${opt.nodeW}' height='${n._h}' rx='8' fill='${visual.fill}' stroke='${visual.stroke}'/><text text-anchor='middle' font-size='12'>${svgTspans(n._lines,tx,n._y+26,15)}</text></g>`;});svg+='</svg>';el.innerHTML=`<div class='graph-scroll'>${svg}</div>`;el.querySelectorAll('[data-review-node-id]').forEach(x=>{x.onclick=()=>onNodeClick&&onNodeClick(x.getAttribute('data-review-node-id'));});el.querySelectorAll('[data-review-edge-index]').forEach(x=>{x.onclick=()=>onEdgeClick&&onEdgeClick(Number(x.getAttribute('data-review-edge-index')));});}
function memoryGraphData(fields){const nodes=[{id:'memory_schema',label:'Memory schema',kind:'root'}],edges=[];(fields||[]).forEach(f=>{nodes.push({id:f.id,label:f.label||f.id,kind:f.memory_type||'memory_field',field:f});edges.push({from:'memory_schema',to:f.id,relation:f.memory_type||'field'});});return{nodes,edges};}
function knowledgeGraphData(items,graphNodes,graphEdges){if((graphNodes||[]).length){return{nodes:(graphNodes||[]).map(n=>({id:n.id,label:n.label||n.id,kind:'graph_node',node:n})),edges:(graphEdges||[]).map(e=>({from:e.from,to:e.to,relation:e.relation||e.relation_type||'relates_to',edge:e}))};}const nodes=[],edges=[];(items||[]).forEach(k=>{nodes.push({id:k.id,label:k.normalized_statement||k.raw_statement||k.id,kind:'knowledge_item',item:k});if(k.domain){const domainId='domain::'+String(k.domain);if(!nodes.find(n=>n.id===domainId))nodes.push({id:domainId,label:k.domain,kind:'domain'});edges.push({from:k.id,to:domainId,relation:'domain'});}});return{nodes,edges};}
function renderMemoryFieldDetail(f,boxId='node_detail'){const box=document.getElementById(boxId);if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(f.id)}</div><div class='label'>${esc(f.label)}</div><div class='detail-kv'><b>Memory type</b><span>${esc(val(f.memory_type))}</span><b>Persistence</b><span>${esc(val(f.persistence))}</span><b>Source</b><span>${esc(val(f.source))}</span><b>Description</b><span>${esc(val(f.description))}</span></div><h3>Schema</h3>${jsonBlock(f.schema||{})}<h3>Update policy</h3>${jsonBlock(f.update_policy||{})}</div>`;}
