function renderGraphNodeDetail(n){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(n.id)}</div><div class='label'>${esc(n.label)}</div><div class='detail-kv'><b>Node type</b><span>${esc(val(n.node_type))}</span><b>Memory type</b><span>${esc(val(n.memory_type))}</span><b>Review</b><span>${esc(n.review&&n.review.status?n.review.status:'')}</span></div><h3>Raw graph node</h3>${jsonBlock(n)}</div>`;}
function renderGraphEdgeDetail(e){const box=document.getElementById('node_detail');if(!box)return;box.innerHTML=`<div class='detail-box'><div class='id'>${esc(e.from)} -> ${esc(e.to)}</div><div class='label'>${esc(val(e.relation)||val(e.relation_type)||'relates_to')}</div><div class='detail-kv'><b>From</b><span>${esc(e.from)}</span><b>To</b><span>${esc(e.to)}</span><b>Relation</b><span>${esc(val(e.relation))}</span><b>Relation type</b><span>${esc(val(e.relation_type))}</span></div><h3>Raw graph edge</h3>${jsonBlock(e)}</div>`;}
function ensureSubworkflowModal(){let modal=document.getElementById('subworkflow_modal');if(modal)return modal;modal=document.createElement('div');modal.id='subworkflow_modal';modal.className='modal hidden';modal.innerHTML="<div class='modal-backdrop' data-close-subworkflow='1'></div><div class='modal-card'><div class='modal-head'><div><h2 id='subworkflow_modal_title'>Subworkflow</h2><div id='subworkflow_modal_ref' class='small'></div></div><button class='btn secondary' data-close-subworkflow='1'>Close</button></div><div class='modal-layout'><div id='subworkflow_modal_body' class='graph modal-graph'></div><aside class='modal-side'><div id='subworkflow_resources' class='detail-box resource-panel'><h2>Knowledge, memory, and resource schema</h2><div class='small'>Click a subworkflow action node to inspect related resources.</div></div><h2>Detail inspector</h2><div id='subworkflow_node_detail' class='detail-box'><div class='small'>Click a subworkflow node or edge to inspect its details.</div></div><div class='feedback-section-gap'></div><h2>Structured feedback</h2><div class='row'><label>Target</label><select id='sw_fb_target'><option>workflow_node</option><option>workflow_edge</option><option>memory_schema</option><option>knowledge_item</option></select></div><div class='row'><label>Target id</label><input id='sw_fb_target_id'></div><div class='row'><label>Field</label><input id='sw_fb_field' value='workflow_node'></div><div class='row'><label>Issue</label><textarea id='sw_fb_issue'></textarea></div><div class='row'><label>Suggestion</label><textarea id='sw_fb_suggestion'></textarea></div><div class='row'><label>Severity</label><select id='sw_fb_severity'><option>medium</option><option>low</option><option>high</option></select></div><div class='btns'><button class='btn' id='sw_addFb'>Add feedback</button></div></aside></div></div>";document.body.appendChild(modal);modal.querySelectorAll('[data-close-subworkflow]').forEach(x=>{x.onclick=closeSubworkflowModal;});document.getElementById('sw_addFb').onclick=addSubworkflowFeedback;return modal;}
function closeSubworkflowModal(){const modal=document.getElementById('subworkflow_modal');if(modal)modal.classList.add('hidden');}
function openSubworkflowModal(parentId){const parent=workflowNodeById(parentId);const modal=ensureSubworkflowModal();const title=document.getElementById('subworkflow_modal_title'),ref=document.getElementById('subworkflow_modal_ref'),body=document.getElementById('subworkflow_modal_body');title.textContent=parent?(parent.label||parent.id):'Subworkflow';ref.textContent=parent&&parent.subworkflow_ref?parent.subworkflow_ref:'';modal.setAttribute('data-parent-id',parentId||'');modal.classList.remove('hidden');document.getElementById('subworkflow_resources').innerHTML='<h2>Knowledge, memory, and resource schema</h2><div class="small">Click a subworkflow action node to inspect related resources.</div>';document.getElementById('subworkflow_node_detail').innerHTML='<div class="small">Click a subworkflow node or edge to inspect its details.</div>';if(!parent||!parent.nested_workflow||!parent.nested_workflow.nodes){body.innerHTML="<div class='notice'>This node references a subworkflow, but the child workflow was not embedded in this standalone review bundle.</div>";return;}currentTaskPreviewId=parentId;const nodes=actionNodes(parent.nested_workflow.nodes||[]),edges=workflowActionEdges(nodes,parent.nested_workflow.edges||[]);drawWorkflowGraph(body,nodes,edges,nodeId=>{renderNestedNodeDetail(parentId,nodeId,'subworkflow_node_detail');setSubworkflowFeedbackTarget(parentId,'workflow_node',nodeId,'workflow.nodes.'+parentId+'.nested_workflow.nodes.'+nodeId);},edgeIndex=>{const edge=workflowEdgeByIndex(edgeIndex,edges);if(!edge)return;renderEdgeDetailObject(edge,'Nested edge inside '+parentId,parent.nested_workflow.nodes||[],'subworkflow_node_detail');setSubworkflowFeedbackTarget(parentId,'workflow_edge',edge.from+'->'+edge.to,'workflow.nodes.'+parentId+'.nested_workflow.edges');});}
function renderTaskTabs(nodes){}
function resourcePanel(){let s=document.getElementById('resources');if(!s){s=document.createElement('div');s.id='resources';s.className='detail-box resource-panel';const detail=document.getElementById('node_detail');if(detail&&detail.parentNode)detail.parentNode.insertBefore(s,detail);else panel.appendChild(s);}return s;}
function relatedWorkflowResourcesFrom(actionId,nodes,edges){const byId={};(nodes||[]).forEach(n=>{byId[n.id]=n;});return(edges||[]).filter(e=>isResourceEdge(e)&&(e.from===actionId||e.to===actionId)).map(e=>{const other=e.from===actionId?byId[e.to]:byId[e.from];return other&&isDataNode(other)?{node:other,edge:e}:null;}).filter(Boolean);}
function relatedWorkflowResources(actionId){return relatedWorkflowResourcesFrom(actionId,data.workflow_graph.nodes||[],data.workflow_graph.edges||[]);}
function relatedKnowledgeItems(actionNode){const refs=new Set(knowledgeRefs(actionNode&&actionNode.knowledge_refs).concat(arrayValue(actionNode&&actionNode.linked_spec_ids).map(String)));return(data.narrative_knowledge.items||[]).filter(k=>refs.has(String(k.id)));}
function relatedMemoryFields(actionNode){const refs=new Set(arrayValue(actionNode&&actionNode.linked_spec_ids).map(String));return(data.memory_schema.fields||[]).filter(f=>refs.has(String(f.id)));}
function renderResourcePanel(actionId){const s=resourcePanel();const action=workflowNodeById(actionId);s.innerHTML='<h2>Knowledge, memory, and resource schema</h2>';if(!action||isDataNode(action)){s.innerHTML+='<div class="small">Click an action node to inspect related knowledge, memory, files, APIs, schemas, and other resource nodes.</div>';return;}s.innerHTML+=`<div class='small'>Showing resources linked to: ${esc(action.label||action.id)}</div>`;const pairs=relatedWorkflowResources(action.id),knowledge=relatedKnowledgeItems(action),memory=relatedMemoryFields(action);if(!pairs.length&&!knowledge.length&&!memory.length){s.innerHTML+='<div class="notice">No linked resource nodes, knowledge items, or memory fields were found for this action node.</div>';return;}const grid=document.createElement('div');grid.className='grid';pairs.forEach(({node,edge})=>{const visual=dataNodeVisual(node);const direction=edge.from===action.id?'action -> resource':'resource -> action';const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(node.id)}</div><div class='label'>${esc(node.label||visual.label)}</div><div class='small'>${esc(visual.label)} | ${esc(val(edge.relation))} | ${esc(direction)}</div><div class='small'>${esc(val(node.source_path||node.retrieval_mode||node.persistence))}</div></button>`;c.onclick=()=>{renderDetailObject(node,'Workflow resource linked by '+val(edge.relation));selectTarget('workflow_node',node.id,'workflow.nodes.'+node.id);};grid.appendChild(c);});knowledge.forEach(k=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(k.id)}</div><div class='label'>${esc(k.type)}</div><div class='small'>${esc(k.normalized_statement||k.raw_statement)}</div></button>`;c.onclick=()=>{renderKnowledgeItemDetail(k);selectTarget('knowledge_item',k.id,'knowledge.items.'+k.id);};grid.appendChild(c);});memory.forEach(f=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(f.id)}</div><div class='label'>${esc(f.label)}</div><div class='small'>${esc(f.memory_type)} | ${esc(f.persistence)}</div><div class='small'>${esc(f.description)}</div></button>`;c.onclick=()=>{renderMemoryFieldDetail(f);selectTarget('memory_schema',f.id,'memory.fields.'+f.id);};grid.appendChild(c);});s.appendChild(grid);}
function renderSubworkflowResourcePanel(parent,actionId){
const s=document.getElementById('subworkflow_resources');if(!s)return;
const nodes=parent&&parent.nested_workflow?parent.nested_workflow.nodes||[]:[];
const edges=parent&&parent.nested_workflow?parent.nested_workflow.edges||[]:[];
const action=(nodes||[]).find(n=>n.id===actionId);
s.innerHTML='<h2>Knowledge, memory, and resource schema</h2>';
if(!action||isDataNode(action)){s.innerHTML+='<div class="small">Click a subworkflow action node to inspect related resources.</div>';return;}
s.innerHTML+=`<div class='small'>Subworkflow resources linked to: ${esc(action.label||action.id)}</div>`;
const pairs=relatedWorkflowResourcesFrom(action.id,nodes,edges),knowledge=relatedKnowledgeItems(action),memory=relatedMemoryFields(action);
if(!pairs.length&&!knowledge.length&&!memory.length){s.innerHTML+='<div class="notice">No linked resource nodes, knowledge items, or memory fields were found for this subworkflow node.</div>';return;}
const grid=document.createElement('div');grid.className='grid';
pairs.forEach(({node,edge})=>{const visual=dataNodeVisual(node);const direction=edge.from===action.id?'action -> resource':'resource -> action';const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(node.id)}</div><div class='label'>${esc(node.label||visual.label)}</div><div class='small'>${esc(visual.label)} | ${esc(val(edge.relation))} | ${esc(direction)}</div><div class='small'>${esc(val(node.source_path||node.retrieval_mode||node.persistence))}</div></button>`;c.onclick=()=>{renderDetailObject(node,'Subworkflow resource linked by '+val(edge.relation),'subworkflow_node_detail');};grid.appendChild(c);});
knowledge.forEach(k=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(k.id)}</div><div class='label'>${esc(k.type)}</div><div class='small'>${esc(k.normalized_statement||k.raw_statement)}</div></button>`;c.onclick=()=>renderKnowledgeItemDetail(k,'subworkflow_node_detail');grid.appendChild(c);});
memory.forEach(f=>{const c=document.createElement('div');c.className='card';c.innerHTML=`<button><div class='id'>${esc(f.id)}</div><div class='label'>${esc(f.label)}</div><div class='small'>${esc(f.memory_type)} | ${esc(f.persistence)}</div><div class='small'>${esc(f.description)}</div></button>`;c.onclick=()=>renderMemoryFieldDetail(f,'subworkflow_node_detail');grid.appendChild(c);});
s.appendChild(grid);
}
function renderWorkflowLegend(){const host=document.getElementById('workflow-legend');if(!host)return;let items=[];if(nodeColorTheme()==='subsystems'){items=['rwm','pg','ae','la','iac'].map(key=>subsystemPalette[key]).concat([{fill:'#EEF2F7',stroke:'#7B8794',label:'Unlabeled'}]);}else{items=[{fill:'#FFF1D6',stroke:'#B45309',label:'Human gate'},{fill:'#E8F3EE',stroke:'#607466',label:'Deterministic automation'},{fill:'#E9E4FB',stroke:'#6D28D9',label:'External stochastic LLM'}];}host.innerHTML=items.map(item=>`<span class='workflow-legend-item'><span class='workflow-swatch' style='background:${item.fill};border-color:${item.stroke}'></span>${esc(item.label)}</span>`).join('');}
function applyWorkflowTheme(){const nodes=workflowActionNodes(),edges=workflowActionEdges(nodes,data.workflow_graph.edges||[]);if(currentWorkflowGraphEl)drawWorkflowGraph(currentWorkflowGraphEl,nodes,edges);renderWorkflowLegend();if(currentTaskPreviewId&&document.getElementById('subworkflow_modal')&&!document.getElementById('subworkflow_modal').classList.contains('hidden'))openSubworkflowModal(currentTaskPreviewId);}
function renderWorkflow(){if(!config.include_workflow)return;const s=section('Workflow graph','workflow');const nodes=workflowActionNodes(),edges=workflowActionEdges(nodes,data.workflow_graph.edges||[]);if(hasBackwardEdges(nodes,edges)&&config.graph_layout!=='process'){const note=document.createElement('div');note.className='notice';note.textContent='This workflow contains backward/loop edges. Use graph_layout = "process" for a clearer loop-aware review diagram.';s.appendChild(note);}const toolbar=document.createElement('div');toolbar.className='workflow-toolbar';toolbar.innerHTML=`<div class='small'>Graph nodes show the action flow only. Knowledge, memory, file, API, schema, and other resource nodes are shown contextually after selecting an action node.</div><div class='row-inline'><label for='workflow-theme-select'>Node colors</label><select id='workflow-theme-select'><option value='default'>Default</option><option value='subsystems'>Subsystems</option></select></div>`;s.appendChild(toolbar);const legend=document.createElement('div');legend.id='workflow-legend';legend.className='workflow-legend';s.appendChild(legend);const g=document.createElement('div');g.className='graph';g.id='workflow_graph_canvas';s.appendChild(g);currentWorkflowGraphEl=g;drawWorkflowGraph(g,nodes,edges);document.getElementById('workflow-theme-select').value=config.node_color_theme||'default';document.getElementById('workflow-theme-select').onchange=e=>{config.node_color_theme=e.target.value;applyWorkflowTheme();};renderWorkflowLegend();renderTaskTabs(nodes);}
function renderFeedback(){if(!config.include_feedback_panel){panel.style.display='none';return;}const schema=data.feedback_schema;panel.innerHTML=`<div id='resources' class='detail-box resource-panel'><h2>Knowledge, memory, and resource schema</h2><div class='small'>Click an action node to inspect related knowledge, memory, files, APIs, schemas, and other resource nodes.</div></div><h2>Detail inspector</h2><div id='node_detail' class='detail-box'><div class='small'>Click a workflow node or edge to inspect its details.</div></div><div class='feedback-section-gap'></div><h2>Structured feedback</h2><div class='row'><label>Target</label><select id='fb_target'>${schema.targets.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='row'><label>Target id</label><input id='fb_target_id'></div><div class='row'><label>Field</label><input id='fb_field' value='workflow_node'></div><div class='row'><label>Issue type</label><select id='fb_issue_type'>${schema.issue_types.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='row'><label>Issue</label><textarea id='fb_issue'></textarea></div><div class='row'><label>Suggestion</label><textarea id='fb_suggestion'></textarea></div><div class='row'><label>Severity</label><select id='fb_severity'>${schema.severities.map(t=>`<option>${esc(t)}</option>`).join('')}</select></div><div class='btns'><button class='btn' id='addFb'>Add feedback</button><button class='btn secondary' id='copyFb'>Copy JSON</button><button class='btn secondary' id='downloadFb'>Download JSON</button></div><h3>Feedback JSON</h3><pre id='fb_json'>{"feedback":[]}</pre><div id='fb_list'></div>`;document.getElementById('addFb').onclick=addFeedback;document.getElementById('copyFb').onclick=()=>navigator.clipboard&&navigator.clipboard.writeText(document.getElementById('fb_json').textContent);document.getElementById('downloadFb').onclick=downloadFeedback;}
function setSideWidth(px){const min=300,max=Math.max(320,wrap.getBoundingClientRect().width-320-10);const clamped=Math.min(max,Math.max(min,Math.round(px)));wrap.style.setProperty('--side-width',clamped+'px');try{localStorage.setItem('agentr-review-side-width',String(clamped));}catch(e){}return clamped;}
function initSplit(){if(!wrap||!splitter)return;try{const saved=Number(localStorage.getItem('agentr-review-side-width'));if(Number.isFinite(saved)&&saved>0)setSideWidth(saved);}catch(e){}splitter.addEventListener('pointerdown',e=>{if(e.button!==0)return;e.preventDefault();splitter.classList.add('dragging');const move=ev=>{setSideWidth(wrap.getBoundingClientRect().right-ev.clientX);};const up=()=>{splitter.classList.remove('dragging');window.removeEventListener('pointermove',move);window.removeEventListener('pointerup',up);};window.addEventListener('pointermove',move);window.addEventListener('pointerup',up);});window.addEventListener('resize',()=>{const current=parseFloat(getComputedStyle(wrap).getPropertyValue('--side-width'));if(Number.isFinite(current)&&current>0)setSideWidth(current);});}
function addFeedback(){const item={id:'fb_'+String(feedback.length+1).padStart(3,'0'),target:fb_target.value,target_id:fb_target_id.value,item_id:fb_target_id.value,field:fb_field.value,issue_type:fb_issue_type.value,issue:fb_issue.value,suggestion:fb_suggestion.value,severity:fb_severity.value,status:'open',source:'human',created_at:new Date().toISOString(),metadata:{review_id:data.review_id}};feedback.push(item);fb_issue.value='';fb_suggestion.value='';renderFeedbackList();}
function setSubworkflowFeedbackTarget(parentId,target,targetId,field){const prefix=parentId?parentId+'::':'';const targetBox=document.getElementById('sw_fb_target'),idBox=document.getElementById('sw_fb_target_id'),fieldBox=document.getElementById('sw_fb_field');if(targetBox)targetBox.value=target;if(idBox)idBox.value=prefix+(targetId||'');if(fieldBox)fieldBox.value=field||target;}
function addSubworkflowFeedback(){const modal=document.getElementById('subworkflow_modal');const parentId=modal?modal.getAttribute('data-parent-id')||'':'';const item={id:'fb_'+String(feedback.length+1).padStart(3,'0'),target:sw_fb_target.value,target_id:sw_fb_target_id.value,item_id:sw_fb_target_id.value,field:sw_fb_field.value,issue_type:'subworkflow_review',issue:sw_fb_issue.value,suggestion:sw_fb_suggestion.value,severity:sw_fb_severity.value,status:'open',source:'human',created_at:new Date().toISOString(),metadata:{review_id:data.review_id,subworkflow_parent_id:parentId}};feedback.push(item);sw_fb_issue.value='';sw_fb_suggestion.value='';renderFeedbackList();}
function renderFeedbackList(){const txt=JSON.stringify({feedback},null,2);document.getElementById('fb_json').textContent=txt;const list=document.getElementById('fb_list');list.innerHTML='';feedback.forEach((f,i)=>{const d=document.createElement('div');d.className='feedback-item';d.innerHTML=`<b>${esc(f.target)}</b> ${esc(f.target_id)}<br>${esc(f.issue)}<br><button class='btn secondary' data-i='${i}'>Delete</button>`;d.querySelector('button').onclick=()=>{feedback.splice(i,1);renderFeedbackList();};list.appendChild(d);});}
function downloadFeedback(){const blob=new Blob([JSON.stringify({feedback},null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=(data.review_id||'agentr_design_feedback')+'.json';a.click();URL.revokeObjectURL(a.href);}
renderWorkflow();renderFeedback();renderResourcePanel();initSplit();const firstNode=workflowActionNodes()[0];if(firstNode)selectWorkflowNode(firstNode.id);
